// Generated by Cypress Author — 2026-06-02
// Updated by Cypress Author — 2026-06-03
// Added sections O–Q: dual-role JSON format rendering (Running Coach / Performance Analyst /
// Summary cards), markdown fallback rendering, and history modal with dual-role items.
// Covers: Analytics AI Card UI states — all sections share the same component;
//         tests use section=weekly_distance (sectionId="weeklydistance") as representative.
//
// AUTH STRATEGY:
//   All describe blocks use setupPageStubs() which:
//     1. cy.setupApiAuthCookies() — sets Supabase auth token cookie
//     2. cy.enableBypass() — sets cypress-bypass cookie to skip middleware auth call
//
// WAIT STRATEGY:
//   Tests do NOT use cy.wait('@getInsights') for initial load — instead they wait for the
//   expected UI element that appears after the insights response is processed.
//
// DESIGN: One describe = one scenario = one page visit (via beforeEach). This eliminates
//   Cypress intercept accumulation issues that arise from multiple before() hooks.
//
// INTERCEPT PRIORITY NOTE:
//   Cypress resolves multiple matching intercepts LIFO (last-in, first-out), but a more
//   specific matcher (e.g. query object) always beats a plain string matcher regardless of
//   order. Therefore, all tests use plain string matchers only — no query-specific matchers.
//
// NOTE: Duplicate-insight guard (preventing re-generate when already pending) is a
//       coverage gap — the backend does not yet expose a guard endpoint; mark BLOCKED.

import { TEST_IDS } from '../../../fixtures/test-ids.js'
import { ROUTES } from '../../../fixtures/routes.js'

const IDS = TEST_IDS.running_analytics
const ANALYTICS_URL = ROUTES.running_analytics
const INSIGHTS_PATH = '/api/running/v1/ai/insights'
const GENERATE_URL = '/api/running/v1/ai/insights/generate'

// Section under test — sectionId strips underscores per AnalyticsAICard logic
const SECTION = 'weekly_distance'

// Convenience selectors for the weekly_distance section card elements
const AI_CARD = `#${IDS.ai_card_weeklydistance}`
const AI_LOADING = `#${IDS.ai_loading_weeklydistance}`
const AI_EMPTY = `#${IDS.ai_empty_weeklydistance}`
const AI_GENERATE_BTN = `#${IDS.ai_generate_btn_weeklydistance}`
const AI_PENDING = `#${IDS.ai_pending_weeklydistance}`
const AI_CONTENT = `#${IDS.ai_content_weeklydistance}`
const AI_ERROR = `#${IDS.ai_error_weeklydistance}`
const AI_RETRY_BTN = `#${IDS.ai_retry_btn_weeklydistance}`
const AI_REFRESH_BTN = `#${IDS.ai_refresh_btn_weeklydistance}`
const AI_STALENESS_BADGE = `#${IDS.ai_staleness_badge_weeklydistance}`
const AI_HISTORY_BTN = `#${IDS.ai_history_btn_weeklydistance}`
const AI_HISTORY_MODAL = `#${IDS.ai_history_modal_weeklydistance}`

// ---------------------------------------------------------------------------
// Shared helpers
// ---------------------------------------------------------------------------

// Completed insight fixture
const completedInsight = (overrides = {}) => ({
  id: 'insight-completed-1',
  status: 'completed',
  is_valid: true,
  content: '## Weekly Distance\n\nGreat consistency this week. Keep it up.',
  data_refs: { section: SECTION },
  created_at: new Date(Date.now() - 1 * 60 * 60 * 1000).toISOString(),
  ...overrides,
})

const pendingInsight = () => ({
  id: 'insight-pending-1',
  insight_type: 'analytics_summary',
  status: 'pending',
  is_valid: false,
  content: null,
  created_at: new Date().toISOString(),
})

const setupPageStubs = () => {
  // Set Supabase auth cookie + bypass middleware auth check
  cy.setupApiAuthCookies()
  cy.enableBypass()

  // Page-level stubs — prevent real Supabase/API calls on page load
  cy.intercept('GET', '**/rest/v1/rt_users*', {
    statusCode: 200,
    body: [{ id: 'test-user-id', onboarding_complete: true }],
  })
  cy.intercept('GET', '/api/running/v1/activities*', {
    statusCode: 200,
    body: { data: [], meta: { total: 0, page: 1, limit: 200 } },
  }).as('getActivities')
  cy.intercept('GET', '/api/running/v1/performance-trends*', {
    statusCode: 200,
    body: { data: [] },
  })
  cy.intercept('GET', '/api/running/v1/dashboard*', {
    statusCode: 200,
    body: {
      data: {
        weekly_stats: {
          current: { distance_m: 0, duration_sec: 0, count: 0, avg_pace_sec_per_km: null },
          prev: { distance_m: 0, duration_sec: 0, count: 0, avg_pace_sec_per_km: null },
        },
        training_load: {
          acwr: null,
          acute_load_7d: null,
          chronic_load_28d: null,
          status: 'no_data',
        },
        recent_activities: [],
        calendar_activities: [],
        health_today: { logged: false, data: null },
      },
    },
  })
  // Stub fetchAnalyticsStaleness — use pathname to match exactly (no query params)
  cy.intercept(
    { method: 'GET', pathname: '/api/running/v1/ai/insights/staleness' },
    {
      statusCode: 200,
      body: { data: { is_stale: false, latest_activity_at: null, latest_insight_at: null } },
    }
  )
}

// Stub the insights list endpoint.
// Uses pathname-based URL object so Cypress matches the path exactly (ignoring query params)
// without accidentally matching /ai/insights/staleness (a sub-path).
const stubInsights = (body) => {
  cy.intercept({ method: 'GET', pathname: INSIGHTS_PATH }, { statusCode: 200, body }).as(
    'getInsights'
  )
}

const visitAndWait = () => {
  cy.viewport(1280, 900)
  cy.visit(ANALYTICS_URL, { failOnStatusCode: false, timeout: 30000 })
  cy.wait('@getActivities', { timeout: 15000 })
  cy.get(AI_CARD, { timeout: 15000 }).scrollIntoView()
}

