// ---------------------------------------------------------------------------

describe('Analytics AI Card UI — auth guard', () => {
  it('unauthenticated visit redirects to /login', () => {
    cy.clearAllCookies()
    cy.clearAllLocalStorage()
    cy.visit(ANALYTICS_URL, { failOnStatusCode: false })
    cy.url().should('include', '/login')
  })
})

// ---------------------------------------------------------------------------
// B. Loading skeleton — insights fetch in-flight
// ---------------------------------------------------------------------------

describe('Analytics AI Card UI — loading skeleton', () => {
  beforeEach(() => {
    setupPageStubs()
    // Delay response so loading skeleton is still visible when assertions run
    cy.intercept({ method: 'GET', pathname: INSIGHTS_PATH }, (req) => {
      req.reply({ delay: 5000, statusCode: 200, body: { data: [] } })
    }).as('getInsights')
    visitAndWait()
  })

  it('renders AI card wrapper and loading skeleton while fetch is in-flight', () => {
    cy.get(AI_CARD).scrollIntoView().should('exist')
    cy.get(AI_LOADING).scrollIntoView().should('exist')
  })
})

