// ---------------------------------------------------------------------------
// D. Generate flow — clicking "Generate Insights" fires POST to generate endpoint
// ---------------------------------------------------------------------------

describe('Analytics AI Card UI — generate flow', () => {
  beforeEach(() => {
    setupPageStubs()
    stubInsights({ data: [] })
    visitAndWait()
    cy.get(AI_EMPTY, { timeout: 10000 }).scrollIntoView()
  })

  it('clicking Generate Insights fires POST with analytics_summary type', () => {
    cy.intercept('POST', GENERATE_URL, {
      statusCode: 200,
      body: { queued: true, message: 'Analytics summary queued' },
    }).as('postGenerate')

    // After POST succeeds, component calls GET again — stub it to return pending
    // so the generate button disappears (empty state is replaced by pending state)
    cy.intercept(
      { method: 'GET', pathname: INSIGHTS_PATH },
      {
        statusCode: 200,
        body: { data: [pendingInsight()] },
      }
    ).as('getInsightsAfterGenerate')

    cy.get(AI_GENERATE_BTN).scrollIntoView().click()
    cy.wait('@postGenerate')

    // POST must have been called with analytics_summary type
    cy.get('@postGenerate')
      .its('request.body')
      .should('deep.include', { type: 'analytics_summary' })

    // After generate, the empty state should be replaced by pending or another state
    cy.get(AI_EMPTY, { timeout: 10000 }).should('not.exist')
  })
})

