// ---------------------------------------------------------------------------
// O. Dual-role JSON format — Running Coach + Performance Analyst + Summary
//    The RoleInsight component parses JSON content produced by the updated
//    generateAnalyticsSummary Inngest function (feat: dual-role format #118).
//    Each section (weekly_distance, pace_trend, etc.) is stored as a JSON
//    string with keys: running_coach, performance_analyst, summary.
// ---------------------------------------------------------------------------

// Dual-role JSON content fixture — matches the schema from buildAnalyticsSummaryPrompt
const dualRoleContent = JSON.stringify({
  running_coach:
    'Focus on building your aerobic base by keeping 80% of runs in Zone 1–2. Your current volume is solid — aim for one quality session per week at tempo effort.',
  performance_analyst:
    'Your weekly distance averaged 42 km over the past 4 weeks with a slight upward trend (+8%). EF sits at 1.72 m/min/bpm, within the moderate range for a developing runner.',
  summary:
    'Solid aerobic volume with room to improve efficiency — prioritize easy pace discipline.',
})

describe('Analytics AI Card UI — dual-role JSON content (Running Coach format)', () => {
  beforeEach(() => {
    setupPageStubs()
    stubInsights({
      data: [
        completedInsight({
          id: 'insight-dual-role',
          content: dualRoleContent,
          created_at: new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString(),
        }),
      ],
    })
    visitAndWait()
    cy.get(AI_CONTENT, { timeout: 10000 }).scrollIntoView()
  })

  it('renders Running Coach card with violet label and coaching advice text', () => {
    // The RoleInsight component renders a violet-bordered card with "Running Coach" label
    cy.get(AI_CONTENT)
      .scrollIntoView()
      .within(() => {
        cy.contains('Running Coach').should('be.visible')
        cy.contains('aerobic base').should('be.visible')
      })
  })

  it('renders Performance Analyst card with blue label and data-driven text', () => {
    cy.get(AI_CONTENT)
      .scrollIntoView()
      .within(() => {
        cy.contains('Performance Analyst').should('be.visible')
        cy.contains('weekly distance').should('be.visible')
      })
  })

  it('renders Summary card with the single most important takeaway', () => {
    cy.get(AI_CONTENT)
      .scrollIntoView()
      .within(() => {
        cy.contains('Summary').should('be.visible')
        cy.contains('Solid aerobic volume').should('be.visible')
      })
  })

  it('shows all three role cards in one content block', () => {
    // All three sections must coexist inside the content container
    cy.get(AI_CONTENT)
      .scrollIntoView()
      .within(() => {
        cy.contains('Running Coach').should('exist')
        cy.contains('Performance Analyst').should('exist')
        cy.contains('Summary').should('exist')
      })
  })
})

// ---------------------------------------------------------------------------
// P. Legacy markdown format fallback
//    When content is NOT valid JSON the RoleInsight component falls back to
//    renderMarkdown — this preserves compatibility with pre-#118 insights.
// ---------------------------------------------------------------------------

describe('Analytics AI Card UI — legacy markdown format (fallback rendering)', () => {
  beforeEach(() => {
    setupPageStubs()
    stubInsights({
      data: [
        completedInsight({
          id: 'insight-legacy-markdown',
          // Old format: plain markdown — not valid JSON
          content:
            '## Weekly Distance\n\nGreat consistency this week. Keep it up.\n\n- 42 km total\n- 4 sessions',
          created_at: new Date(Date.now() - 1 * 60 * 60 * 1000).toISOString(),
        }),
      ],
    })
    visitAndWait()
    cy.get(AI_CONTENT, { timeout: 10000 }).scrollIntoView()
  })

  it('renders legacy markdown content without three role cards', () => {
    // Fallback path: text should appear but no role-specific labels
    cy.get(AI_CONTENT)
      .scrollIntoView()
      .within(() => {
        cy.contains('Great consistency this week').should('be.visible')
        // Role-specific headings must NOT appear in the markdown fallback
        cy.contains('Running Coach').should('not.exist')
        cy.contains('Performance Analyst').should('not.exist')
      })
  })
})

// ---------------------------------------------------------------------------
// Q. History modal — dual-role JSON format items render correctly
//    History items expand via accordion; each uses RoleInsight so the
//    dual-role cards must also render inside the history sheet.
// ---------------------------------------------------------------------------

describe('Analytics AI Card UI — history modal with dual-role JSON items', () => {
  beforeEach(() => {
    setupPageStubs()
    stubInsights({
      data: [
        // Most recent — dual-role JSON format
        completedInsight({
          id: 'insight-dual-recent',
          content: dualRoleContent,
          created_at: new Date(Date.now() - 1 * 60 * 60 * 1000).toISOString(),
        }),
        // Older — also dual-role JSON format
        completedInsight({
          id: 'insight-dual-older',
          content: JSON.stringify({
            running_coach: 'Last week you ran well. Consider adding one long run.',
            performance_analyst:
              'Volume was 38 km — slightly below target. Pace was consistent across sessions.',
            summary: 'Consistent week — add volume gradually.',
          }),
          created_at: new Date(Date.now() - 8 * 24 * 60 * 60 * 1000).toISOString(),
        }),
      ],
    })
    visitAndWait()
    cy.get(AI_CONTENT, { timeout: 10000 }).scrollIntoView()
  })

  it('opens history modal and expanding an item renders dual-role cards', () => {
    // Open history modal — button is visible because ≥2 completed insights
    cy.get(AI_HISTORY_BTN).scrollIntoView().should('be.visible').click()
    cy.get(AI_HISTORY_MODAL).should('be.visible')

    // Expand the first history accordion item
    cy.get(AI_HISTORY_MODAL).within(() => {
      cy.get('button[aria-expanded]').first().click()
      // After expanding, the dual-role cards should appear inside the modal
      cy.contains('Running Coach').should('be.visible')
      cy.contains('Performance Analyst').should('be.visible')
      cy.contains('Summary').should('be.visible')
    })
  })
})
